349	    fn join_sequence(
350	        a: &mut Expression<'a>,
351	        b: &mut Expression<'a>,
352	        ctx: &TraverseCtx<'a>,
353	    ) -> Expression<'a> {
354	        let a = a.take_in(ctx.ast);
355	        let b = b.take_in(ctx.ast);
356	        if let Expression::SequenceExpression(mut sequence_expr) = a {
357	            // `(a, b); c`
358	            sequence_expr.expressions.push(b);
359	            return Expression::SequenceExpression(sequence_expr);
360	        }
361	        let span = a.span();
362	        let exprs = if let Expression::SequenceExpression(sequence_expr) = b {
363	            // `a; (b, c)`
364	            ctx.ast.vec_from_iter(std::iter::once(a).chain(sequence_expr.unbox().expressions))
365	        } else {
366	            // `a; b`
367	            ctx.ast.vec_from_array([a, b])
368	        };
369	        ctx.ast.expression_sequence(span, exprs)
370	    }
371	
372	    fn jump_stmts_look_the_same(left: &Statement<'a>, right: &Statement<'a>) -> bool {
373	        if left.is_jump_statement() && right.is_jump_statement() {
374	            return left.content_eq(right);
375	        }
376	        false
377	    }
