446	    fn handle_expression_statement(
447	        mut expr_stmt: Box<'a, ExpressionStatement<'a>>,
448	        result: &mut Vec<'a, Statement<'a>>,
449	
450	        ctx: &mut TraverseCtx<'a>,
451	    ) {
452	        let changed = Self::substitute_single_use_symbol_in_statement(
453	            &mut expr_stmt.expression,
454	            result,
455	            ctx,
456	            false,
457	        );
458	        if changed {
459	            ctx.state.changed = true;
460	        }
461	
462	        if ctx.options().sequences
463	            && let Some(Statement::ExpressionStatement(prev_expr_stmt)) = result.last_mut()
464	        {
465	            let a = &mut prev_expr_stmt.expression;
466	            let b = &mut expr_stmt.expression;
467	            expr_stmt.expression = Self::join_sequence(a, b, ctx);
468	            result.pop();
469	            ctx.state.changed = true;
470	        }
471	        // "var a; a = b();" => "var a = b();"
472	        match &mut expr_stmt.expression {
473	            Expression::AssignmentExpression(assign_expr) => {
474	                let merged = Self::merge_assignment_to_declaration(assign_expr, result, ctx);
475	                if merged {
476	                    ctx.state.changed = true;
477	                    return;
478	                }
479	            }
480	            Expression::SequenceExpression(sequence_expr)
481	                if result
482	                    .last()
483	                    .is_some_and(|stmt| matches!(stmt, Statement::VariableDeclaration(_))) =>
484	            {
485	                let first_non_merged_index =
486	                    sequence_expr.expressions.iter_mut().position(|expr| {
487	                        if let Expression::AssignmentExpression(assign_expr) = expr {
488	                            !Self::merge_assignment_to_declaration(assign_expr, result, ctx)
489	                        } else {
490	                            true
491	                        }
492	                    });
493	                let sequence_len = sequence_expr.expressions.len();
494	                match first_non_merged_index {
495	                    None => {
496	                        // all elements are merged
497	                        ctx.state.changed = true;
498	                        return;
499	                    }
500	                    Some(val) if val == sequence_len - 1 => {
501	                        // all elements are merged except for the last expression
502	                        let last_expr = sequence_expr.expressions.pop().unwrap();
503	                        result.push(ctx.ast.statement_expression(last_expr.span(), last_expr));
504	                        ctx.state.changed = true;
505	                        return;
506	                    }
507	                    Some(0) => {
508	                        // no elements are merged
509	                    }
510	                    Some(val) => {
511	                        sequence_expr.expressions.drain(0..val);
512	                        ctx.state.changed = true;
513	                    }
514	                }
515	            }
516	            _ => {}
517	        }
518	
519	        result.push(Statement::ExpressionStatement(expr_stmt));
520	    }
521	
522	    fn merge_assignment_to_declaration(
523	        assign_expr: &mut AssignmentExpression<'a>,
524	        result: &mut Vec<'a, Statement<'a>>,
525	        ctx: &TraverseCtx<'a>,
526	    ) -> bool {
527	        if assign_expr.operator != AssignmentOperator::Assign {
528	            return false;
529	        }
530	        let AssignmentTarget::AssignmentTargetIdentifier(id) = &assign_expr.left else {
531	            return false;
532	        };
533	        let Some(Statement::VariableDeclaration(var_decl)) = result.last_mut() else {
534	            return false;
535	        };
536	        if !matches!(&var_decl.kind, VariableDeclarationKind::Var | VariableDeclarationKind::Let) {
537	            return false;
538	        }
539	        for decl in var_decl.declarations.iter_mut().rev() {
540	            let BindingPattern::BindingIdentifier(kind) = &decl.id else {
541	                break;
542	            };
543	            if kind.name == id.name {
544	                if decl.init.is_none()
545	                    && (decl.kind == VariableDeclarationKind::Var
546	                        || assign_expr.right.is_literal_value(true, ctx))
547	                {
548	                    // "var a; a = b();" => "var a = b();"
549	                    decl.init = Some(assign_expr.right.take_in(ctx.ast));
550	                    return true;
551	                }
552	                // Note it is not possible to compress like:
553	                // - "var a = b(); a = c();" => "var a = (b(), c());"
554	                //   This is not possible as we need to consider cases when `c()` accesses `a`
555	                // - "var a = 1; a = b();" => "var a = b();"
556	                //   This is not possible as we need to consider cases when `b()` accesses `a`
557	                // - "let a; a = foo(a);" => "let a = foo(a);"
558	                //   This is not possible as TDZ error would be introduced
559	                break;
560	            }
561	            // should not move assignment above variables with initializer to keep the execution order
562	            if decl.init.is_some() {
563	                break;
564	            }
565	            // should not move assignment above other variables for let
566	            // this could cause TDZ errors (e.g. `let a, b; b = a;`)
567	            if decl.kind == VariableDeclarationKind::Let {
568	                break;
569	            }
570	        }
571	        false
572	    }
