574	    fn handle_switch_statement(
575	        mut switch_stmt: Box<'a, SwitchStatement<'a>>,
576	        result: &mut Vec<'a, Statement<'a>>,
577	
578	        ctx: &mut TraverseCtx<'a>,
579	    ) {
580	        let changed = Self::substitute_single_use_symbol_in_statement(
581	            &mut switch_stmt.discriminant,
582	            result,
583	            ctx,
584	            false,
585	        );
586	        if changed {
587	            ctx.state.changed = true;
588	        }
589	
590	        if ctx.options().sequences
591	            && let Some(Statement::ExpressionStatement(prev_expr_stmt)) = result.last_mut()
592	        {
593	            let a = &mut prev_expr_stmt.expression;
594	            let b = &mut switch_stmt.discriminant;
595	            switch_stmt.discriminant = Self::join_sequence(a, b, ctx);
596	            result.pop();
597	            ctx.state.changed = true;
598	        }
599	
600	        // Prune empty case clauses before a trailing default
601	        // e.g., `switch (x) { case 0: foo(); break; case 1: default: bar() }`
602	        // => `switch (x) { case 0: foo(); break; default: bar() }`
603	        // https://github.com/evanw/esbuild/commit/add452ed51333953dd38a26f28a775bb220ea2e9
604	        if let Some(last_case) = switch_stmt.cases.last()
605	            && last_case.test.is_none()
606	        {
607	            let default_idx = switch_stmt.cases.len() - 1;
608	            let mut first_empty_idx = default_idx;
609	            // Iterate backward through preceding cases
610	            while first_empty_idx > 0 {
611	                let case = &switch_stmt.cases[first_empty_idx - 1];
612	                // Only remove empty cases with primitive literal tests
613	                if case.consequent.is_empty()
614	                    && case.test.as_ref().is_some_and(Expression::is_literal)
615	                {
616	                    first_empty_idx -= 1;
617	                } else {
618	                    break;
619	                }
620	            }
621	            // If we found cases to remove, keep cases [0..first_empty_idx] + [default]
622	            if first_empty_idx < default_idx {
623	                let default_case = switch_stmt.cases.pop().unwrap();
624	                switch_stmt.cases.truncate(first_empty_idx);
625	                switch_stmt.cases.push(default_case);
626	                ctx.state.changed = true;
627	            }
628	        }
629	
630	        result.push(Statement::SwitchStatement(switch_stmt));
