633	    fn handle_if_statement(
634	        i: usize,
635	        stmts: &mut Vec<'a, Statement<'a>>,
636	        mut if_stmt: Box<'a, IfStatement<'a>>,
637	        result: &mut Vec<'a, Statement<'a>>,
638	
639	        ctx: &mut TraverseCtx<'a>,
640	    ) -> ControlFlow<()> {
641	        let changed =
642	            Self::substitute_single_use_symbol_in_statement(&mut if_stmt.test, result, ctx, false);
643	        if changed {
644	            ctx.state.changed = true;
645	        }
646	
647	        // Absorb a previous expression statement
648	        if ctx.options().sequences {
649	            if let Some(Statement::ExpressionStatement(prev_expr_stmt)) = result.last_mut() {
650	                let a = &mut prev_expr_stmt.expression;
651	                let b = &mut if_stmt.test;
652	                if_stmt.test = Self::join_sequence(a, b, ctx);
653	                result.pop();
654	                ctx.state.changed = true;
655	            }
656	
657	            if if_stmt.consequent.is_jump_statement() {
658	                // Absorb a previous if statement
659	                if let Some(Statement::IfStatement(prev_if_stmt)) = result.last_mut()
660	                    && prev_if_stmt.alternate.is_none()
661	                    && Self::jump_stmts_look_the_same(&prev_if_stmt.consequent, &if_stmt.consequent)
662	                {
663	                    // "if (a) break c; if (b) break c;" => "if (a || b) break c;"
664	                    // "if (a) continue c; if (b) continue c;" => "if (a || b) continue c;"
665	                    // "if (a) return c; if (b) return c;" => "if (a || b) return c;"
666	                    // "if (a) throw c; if (b) throw c;" => "if (a || b) throw c;"
667	                    if_stmt.test = Self::join_with_left_associative_op(
668	                        if_stmt.test.span(),
669	                        LogicalOperator::Or,
670	                        prev_if_stmt.test.take_in(ctx.ast),
671	                        if_stmt.test.take_in(ctx.ast),
672	                        ctx,
673	                    );
674	                    result.pop();
675	                    ctx.state.changed = true;
676	                }
677	
678	                let mut optimize_implicit_jump = false;
679	                // "while (x) { if (y) continue; z(); }" => "while (x) { if (!y) z(); }"
680	                // "while (x) { if (y) continue; else z(); w(); }" => "while (x) { if (!y) { z(); w(); } }" => "for (; x;) !y && (z(), w());"
681	                if ctx.ancestors().nth(1).is_some_and(|v| {
682	                    v.is_for_statement() || v.is_for_in_statement() || v.is_for_of_statement()
683	                }) && let Statement::ContinueStatement(continue_stmt) = &if_stmt.consequent
684	                    && continue_stmt.label.is_none()
685	                {
686	                    optimize_implicit_jump = true;
687	                }
688	
689	                // "let x = () => { if (y) return; z(); };" => "let x = () => { if (!y) z(); };"
690	                // "let x = () => { if (y) return; else z(); w(); };" => "let x = () => { if (!y) { z(); w(); } };" => "let x = () => { !y && (z(), w()); };"
691	                if ctx.parent().is_function_body()
692	                    && let Statement::ReturnStatement(return_stmt) = &if_stmt.consequent
693	                    && return_stmt.argument.is_none()
694	                {
695	                    optimize_implicit_jump = true;
696	                }
697	                if optimize_implicit_jump {
698	                    // Don't do this transformation if the branch condition could
699	                    // potentially access symbols declared later on on this scope below.
700	                    // If so, inverting the branch condition and nesting statements after
701	                    // this in a block would break that access which is a behavior change.
702	                    //
703	                    //   // This transformation is incorrect
704	                    //   if (a()) return; function a() {}
705	                    //   if (!a()) { function a() {} }
706	                    //
707	                    //   // This transformation is incorrect
708	                    //   if (a(() => b)) return; let b;
709	                    //   if (a(() => b)) { let b; }
710	                    //
711	                    let mut can_move_branch_condition_outside_scope = true;
712	                    if let Some(alternate) = &if_stmt.alternate
713	                        && Self::statement_cares_about_scope(alternate)
714	                    {
715	                        can_move_branch_condition_outside_scope = false;
716	                    }
717	                    if let Some(stmts) = stmts.get(i + 1..) {
718	                        for stmt in stmts {
719	                            if Self::statement_cares_about_scope(stmt) {
720	                                can_move_branch_condition_outside_scope = false;
721	                                break;
722	                            }
723	                        }
724	                    }
725	
726	                    if can_move_branch_condition_outside_scope {
727	                        let drained_stmts = stmts.drain(i + 1..);
728	                        let mut body = if let Some(alternate) = if_stmt.alternate.take() {
729	                            ctx.ast.vec_from_iter(iter::once(alternate).chain(drained_stmts))
730	                        } else {
731	                            ctx.ast.vec_from_iter(drained_stmts)
732	                        };
733	
734	                        Self::minimize_statements(&mut body, ctx);
735	                        let span = if body.is_empty() {
736	                            if_stmt.consequent.span()
737	                        } else {
738	                            body[0].span()
739	                        };
740	                        let test = if_stmt.test.take_in(ctx.ast);
741	                        let mut test = Self::minimize_not(test.span(), test, ctx);
742	                        Self::minimize_expression_in_boolean_context(&mut test, ctx);
743	                        let consequent = if body.len() == 1 {
744	                            body.remove(0)
745	                        } else {
746	                            let scope_id = ctx.create_child_scope_of_current(ScopeFlags::empty());
747	                            let block_stmt =
748	                                ctx.ast.block_statement_with_scope_id(span, body, scope_id);
749	                            Statement::BlockStatement(ctx.ast.alloc(block_stmt))
750	                        };
751	                        let mut if_stmt = ctx.ast.if_statement(test.span(), test, consequent, None);
752	                        let if_stmt = Self::try_minimize_if(&mut if_stmt, ctx)
753	                            .unwrap_or_else(|| Statement::IfStatement(ctx.ast.alloc(if_stmt)));
754	                        result.push(if_stmt);
755	                        ctx.state.changed = true;
756	                        return ControlFlow::Break(());
757	                    }
758	                }
759	
760	                if if_stmt.alternate.is_some() {
761	                    // "if (a) return b; else if (c) return d; else return e;" => "if (a) return b; if (c) return d; return e;"
762	                    result.push(Statement::IfStatement(if_stmt));
763	                    loop {
764	                        if let Some(Statement::IfStatement(if_stmt)) = result.last_mut()
765	                            && if_stmt.consequent.is_jump_statement()
766	                            && let Some(stmt) = if_stmt.alternate.take()
767	                        {
768	                            if let Statement::BlockStatement(block_stmt) = stmt {
769	                                Self::handle_block(result, block_stmt, ctx);
770	                            } else {
771	                                result.push(stmt);
772	                                ctx.state.changed = true;
773	                            }
774	                            continue;
775	                        }
776	                        break;
777	                    }
778	                    return ControlFlow::Continue(());
779	                }
780	            }
781	        }
782	
783	        result.push(Statement::IfStatement(if_stmt));
784	        ControlFlow::Continue(())
785	    }
