787	    fn handle_return_statement(
788	        mut ret_stmt: Box<'a, ReturnStatement<'a>>,
789	        result: &mut Vec<'a, Statement<'a>>,
790	        is_control_flow_dead: &mut bool,
791	
792	        ctx: &mut TraverseCtx<'a>,
793	    ) {
794	        if let Some(ret_argument_expr) = &mut ret_stmt.argument {
795	            let changed = Self::substitute_single_use_symbol_in_statement(
796	                ret_argument_expr,
797	                result,
798	                ctx,
799	                false,
800	            );
801	            if changed {
802	                ctx.state.changed = true;
803	            }
804	        }
805	
806	        if let Some(argument) = &mut ret_stmt.argument
807	            && argument.value_type(ctx) == ValueType::Undefined
808	            // `return undefined` has a different semantic in async generator function.
809	            && !ctx.is_closest_function_scope_an_async_generator()
810	        {
811	            ctx.state.changed = true;
812	            if argument.may_have_side_effects(ctx) {
813	                if ctx.options().sequences
814	                    && let Some(Statement::ExpressionStatement(prev_expr_stmt)) = result.last_mut()
815	                {
816	                    let a = &mut prev_expr_stmt.expression;
817	                    prev_expr_stmt.expression = Self::join_sequence(a, argument, ctx);
818	                } else {
819	                    result.push(
820	                        ctx.ast.statement_expression(argument.span(), argument.take_in(ctx.ast)),
821	                    );
822	                }
823	            }
824	            ret_stmt.argument = None;
825	            result.push(Statement::ReturnStatement(ret_stmt));
826	            *is_control_flow_dead = true;
827	            return;
828	        }
829	
830	        if ctx.options().sequences
831	            && let Some(Statement::ExpressionStatement(prev_expr_stmt)) = result.last_mut()
832	            && let Some(argument) = &mut ret_stmt.argument
833	        {
834	            let a = &mut prev_expr_stmt.expression;
835	            *argument = Self::join_sequence(a, argument, ctx);
836	            result.pop();
837	            ctx.state.changed = true;
838	        }
839	        result.push(Statement::ReturnStatement(ret_stmt));
840	        *is_control_flow_dead = true;
841	    }
