873	    fn handle_for_statement(
874	        mut for_stmt: Box<'a, ForStatement<'a>>,
875	        result: &mut Vec<'a, Statement<'a>>,
876	
877	        ctx: &mut TraverseCtx<'a>,
878	    ) {
879	        if let Some(init) = &mut for_stmt.init {
880	            match init {
881	                ForStatementInit::VariableDeclaration(var_decl) => {
882	                    if let Some(first_decl) = var_decl.declarations.first_mut()
883	                        && let Some(first_decl_init) = first_decl.init.as_mut()
884	                    {
885	                        let is_block_scoped_decl = !first_decl.kind.is_var();
886	                        let changed = Self::substitute_single_use_symbol_in_statement(
887	                            first_decl_init,
888	                            result,
889	                            ctx,
890	                            is_block_scoped_decl,
891	                        );
892	                        if changed {
893	                            ctx.state.changed = true;
894	                        }
895	                    }
896	                    if Self::substitute_single_use_symbol_within_declaration(
897	                        var_decl.kind,
898	                        &mut var_decl.declarations,
899	                        ctx,
900	                    ) {
901	                        ctx.state.changed = true;
902	                    }
903	                }
904	                match_expression!(ForStatementInit) => {
905	                    let init = init.to_expression_mut();
906	                    let changed =
907	                        Self::substitute_single_use_symbol_in_statement(init, result, ctx, false);
908	                    if changed {
909	                        ctx.state.changed = true;
910	                    }
911	                }
912	            }
913	        }
914	
915	        if let Some(ForStatementInit::VariableDeclaration(var_decl)) = &mut for_stmt.init {
916	            let old_len = var_decl.declarations.len();
917	            var_decl.declarations.retain(|decl| {
918	                !Self::should_remove_unused_declarator(decl, ctx)
919	                    || decl.init.as_ref().is_some_and(|init| init.may_have_side_effects(ctx))
920	            });
921	            if old_len != var_decl.declarations.len() {
922	                if var_decl.declarations.is_empty() {
923	                    for_stmt.init = None;
924	                }
925	                ctx.state.changed = true;
926	            }
927	        }
928	
929	        if ctx.options().sequences {
930	            match result.last_mut() {
931	                Some(Statement::ExpressionStatement(prev_expr_stmt)) => {
932	                    if let Some(init) = &mut for_stmt.init {
933	                        if let Some(init) = init.as_expression_mut() {
934	                            let a = &mut prev_expr_stmt.expression;
935	                            *init = Self::join_sequence(a, init, ctx);
936	                            result.pop();
937	                            ctx.state.changed = true;
938	                        }
939	                    } else {
940	                        for_stmt.init = Some(ForStatementInit::from(
941	                            prev_expr_stmt.expression.take_in(ctx.ast),
942	                        ));
943	                        result.pop();
944	                        ctx.state.changed = true;
945	                    }
946	                }
947	                Some(Statement::VariableDeclaration(prev_var_decl)) => {
948	                    if let Some(init) = &mut for_stmt.init {
949	                        if prev_var_decl.kind.is_var()
950	                            && let ForStatementInit::VariableDeclaration(var_decl) = init
951	                            && var_decl.kind.is_var()
952	                        {
953	                            var_decl
954	                                .declarations
955	                                .splice(0..0, prev_var_decl.declarations.drain(..));
956	                            result.pop();
957	                            ctx.state.changed = true;
958	                        }
959	                    } else if prev_var_decl.kind.is_var() {
960	                        let Some(Statement::VariableDeclaration(prev_var_decl)) = result.pop()
961	                        else {
962	                            unreachable!()
963	                        };
964	                        for_stmt.init = Some(ForStatementInit::VariableDeclaration(prev_var_decl));
965	                        ctx.state.changed = true;
966	                    }
967	                }
968	                _ => {}
969	            }
970	        }
971	        result.push(Statement::ForStatement(for_stmt));
972	    }
