974	    fn handle_for_in_statement(
975	        mut for_in_stmt: Box<'a, ForInStatement<'a>>,
976	        result: &mut Vec<'a, Statement<'a>>,
977	
978	        ctx: &mut TraverseCtx<'a>,
979	    ) {
980	        // Annex B.3.5 allows initializers in non-strict mode
981	        // <https://tc39.es/ecma262/multipage/additional-ecmascript-features-for-web-browsers.html#sec-initializers-in-forin-statement-heads>
982	        // That is evaluated before the right hand side is evaluated. So, in that case, skip the single use substitution.
983	        if !matches!(&for_in_stmt.left, ForStatementLeft::VariableDeclaration(var_decl) if var_decl.has_init())
984	        {
985	            let is_block_scoped_decl = matches!(&for_in_stmt.left, ForStatementLeft::VariableDeclaration(var_decl) if !var_decl.kind.is_var());
986	            let changed = Self::substitute_single_use_symbol_in_statement(
987	                &mut for_in_stmt.right,
988	                result,
989	                ctx,
990	                is_block_scoped_decl,
991	            );
992	            if changed {
993	                ctx.state.changed = true;
994	            }
995	        }
996	
997	        if ctx.options().sequences {
998	            match result.last_mut() {
999	                // "a; for (var b in c) d" => "for (var b in a, c) d"
1000	                Some(Statement::ExpressionStatement(prev_expr_stmt)) => {
1001	                    // Annex B.3.5 allows initializers in non-strict mode
1002	                    // <https://tc39.es/ecma262/multipage/additional-ecmascript-features-for-web-browsers.html#sec-initializers-in-forin-statement-heads>
1003	                    // If there's a side-effectful initializer, we should not move the previous statement inside.
1004	                    let has_side_effectful_initializer = {
1005	                        if let ForStatementLeft::VariableDeclaration(var_decl) = &for_in_stmt.left {
1006	                            if var_decl.declarations.len() == 1 {
1007	                                // only var can have a initializer
1008	                                var_decl.kind.is_var()
1009	                                    && var_decl.declarations[0]
1010	                                        .init
1011	                                        .as_ref()
1012	                                        .is_some_and(|init| init.may_have_side_effects(ctx))
1013	                            } else {
1014	                                // the spec does not allow multiple declarations though
1015	                                true
1016	                            }
1017	                        } else {
1018	                            false
1019	                        }
1020	                    };
1021	                    // Only allow inlining when the for-in variable is declared with `var`.
1022	                    // Block-scoped declarations (let/const) can cause variable shadowing issues
1023	                    // where the inlined expression might reference a variable with the same name
1024	                    // as the for-in variable, but after inlining, it would incorrectly refer to
1025	                    // the shadowed for-in variable instead.
1026	                    // See: https://github.com/oxc-project/oxc/issues/18650
1027	                    let is_block_scoped = matches!(&for_in_stmt.left, ForStatementLeft::VariableDeclaration(var_decl) if !var_decl.kind.is_var());
1028	                    if !has_side_effectful_initializer && !is_block_scoped {
1029	                        let a = &mut prev_expr_stmt.expression;
1030	                        for_in_stmt.right = Self::join_sequence(a, &mut for_in_stmt.right, ctx);
1031	                        result.pop();
1032	                        ctx.state.changed = true;
1033	                    }
1034	                }
1035	                // "var a; for (a in b) c" => "for (var a in b) c"
1036	                Some(Statement::VariableDeclaration(prev_var_decl)) => {
1037	                    if let ForStatementLeft::AssignmentTargetIdentifier(id) = &for_in_stmt.left {
1038	                        let prev_var_decl_no_init_item = {
1039	                            if prev_var_decl.kind.is_var()
1040	                                && prev_var_decl.declarations.len() == 1
1041	                                && prev_var_decl.declarations[0].init.is_none()
1042	                            {
1043	                                Some(&prev_var_decl.declarations[0])
1044	                            } else {
1045	                                None
1046	                            }
1047	                        };
1048	                        if let Some(prev_var_decl_item) = prev_var_decl_no_init_item
1049	                            && let BindingPattern::BindingIdentifier(decl_id) =
1050	                                &prev_var_decl_item.id
1051	                            && id.name == decl_id.name
1052	                        {
1053	                            let Some(Statement::VariableDeclaration(prev_var_decl)) = result.pop()
1054	                            else {
1055	                                unreachable!()
1056	                            };
1057	                            for_in_stmt.left = ForStatementLeft::VariableDeclaration(prev_var_decl);
1058	                            ctx.state.changed = true;
1059	                        }
1060	                    }
1061	                }
1062	                _ => {}
1063	            }
1064	        }
1065	        result.push(Statement::ForInStatement(for_in_stmt));
1066	    }
