1068	    fn handle_for_of_statement(
1069	        mut for_of_stmt: Box<'a, ForOfStatement<'a>>,
1070	        result: &mut Vec<'a, Statement<'a>>,
1071	        ctx: &mut TraverseCtx<'a>,
1072	    ) {
1073	        let is_block_scoped_decl = matches!(&for_of_stmt.left, ForStatementLeft::VariableDeclaration(var_decl) if !var_decl.kind.is_var());
1074	        let changed = Self::substitute_single_use_symbol_in_statement(
1075	            &mut for_of_stmt.right,
1076	            result,
1077	            ctx,
1078	            is_block_scoped_decl,
1079	        );
