1099	                && let BindingPattern::BindingIdentifier(decl_id) = &prev_var_decl_item.id
1100	                && id.name == decl_id.name
1101	            {
1102	                let Some(Statement::VariableDeclaration(prev_var_decl)) = result.pop() else {
1103	                    unreachable!()
1104	                };
1105	                for_of_stmt.left = ForStatementLeft::VariableDeclaration(prev_var_decl);
