1127	    /// `statementCaresAboutScope`: <https://github.com/evanw/esbuild/blob/v0.24.2/internal/js_ast/js_parser.go#L9767>
1128	    pub fn statement_cares_about_scope(stmt: &Statement<'a>) -> bool {
1129	        match stmt {
1130	            Statement::BlockStatement(_)
1131	            | Statement::EmptyStatement(_)
1132	            | Statement::DebuggerStatement(_)
1133	            | Statement::ExpressionStatement(_)
1134	            | Statement::IfStatement(_)
1135	            | Statement::ForStatement(_)
1136	            | Statement::ForInStatement(_)
1137	            | Statement::ForOfStatement(_)
1138	            | Statement::DoWhileStatement(_)
1139	            | Statement::WhileStatement(_)
1140	            | Statement::WithStatement(_)
1141	            | Statement::TryStatement(_)
1142	            | Statement::SwitchStatement(_)
1143	            | Statement::ReturnStatement(_)
1144	            | Statement::ThrowStatement(_)
1145	            | Statement::BreakStatement(_)
1146	            | Statement::ContinueStatement(_)
1147	            | Statement::LabeledStatement(_) => false,
1148	            Statement::VariableDeclaration(decl) => !decl.kind.is_var(),
1149	            _ => true,
1150	        }
1151	    }
